import numpy as np

def transform_matrix(A: list[list[int|float]], T: list[list[int|float]], S: list[list[int|float]]) -> list[list[int|float]]:
    def determinant(matrix):
        n = len(matrix)
        mat = [row[:] for row in matrix]
        det = 1.0
        for col in range(n):
            pivot = -1
            for row in range(col, n):
                if abs(mat[row][col]) > 1e-10:
                    pivot = row
                    break
            if pivot == -1:
                return 0.0
            if pivot != col:
                mat[col], mat[pivot] = mat[pivot], mat[col]
                det *= -1
            det *= mat[col][col]
            for row in range(col + 1, n):
                factor = mat[row][col] / mat[col][col]
                for k in range(col, n):
                    mat[row][k] -= factor * mat[col][k]
        return det

    def invert_matrix(matrix):
        n = len(matrix)
        aug = [row[:] + [1.0 if i == j else 0.0 for j in range(n)] for i, row in enumerate(matrix)]
        for col in range(n):
            pivot = -1
            for row in range(col, n):
                if abs(aug[row][col]) > 1e-10:
                    pivot = row
                    break
            if pivot == -1:
                return None
            aug[col], aug[pivot] = aug[pivot], aug[col]
            scale = aug[col][col]
            aug[col] = [x / scale for x in aug[col]]
            for row in range(n):
                if row != col:
                    factor = aug[row][col]
                    aug[row] = [aug[row][k] - factor * aug[col][k] for k in range(2 * n)]
        return [row[n:] for row in aug]

    def mat_mul(A, B):
        rows_A, cols_A = len(A), len(A[0])
        cols_B = len(B[0])
        result = [[sum(A[i][k] * B[k][j] for k in range(cols_A)) for j in range(cols_B)] for i in range(rows_A)]
        return result

    try:
        if determinant(T) == 0 or determinant(S) == 0:
            return -1
        T_inv = invert_matrix(T)
        if T_inv is None:
            return -1
        result = mat_mul(mat_mul(T_inv, A), S)
        return [[round(x, 10) for x in row] for row in result]
    except Exception:
        return -1

